custom_css:
/*
 * ═══════════════════════════════════════════════════════════════
 *  HALE COURTSIDE — neon violet/cyan, arena at midnight, MVP behavior
 *  HALE UNIVERSITY · EST. 1856 · NYC — but make it filthy rich 💸
 *  ultra-modern glass · phone-core · varsity luxury · zero classicism
 *  avatars sized like Midnight Ocean · input sized like Bayou
 *  icons swapped like Heartbeat · meta chips like wine & cherry pie
 * ═══════════════════════════════════════════════════════════════
 */

@import url('https://fonts.googleapis.com/css2?family=Manrope:ital,wght@0,300..800&family=Unbounded:wght@300..900&family=JetBrains+Mono:ital,wght@0,400;0,700;1,400&display=swap');

/* ───────────────────────── PALETTE + STRINGS ───────────────────────── */
:root {
  --hu-text: #ece9f7;
  --hu-dim: #9a93b8;
  --hu-em: #a78bfa;
  --hu-quote: #c4b5fd;
  --hu-accent: #a78bfa;
  --hu-accent-2: #22d3ee;
  --hu-icon: #c9c2e8;
  --hu-check-color: #0d0a16;
  --hu-topbar: rgba(9, 7, 16, 0.85);
  --hu-panel: rgba(13, 10, 22, 0.82);
  --hu-panel-solid: rgba(13, 10, 22, 0.96);
  --hu-card: rgba(17, 13, 30, 0.62);
  --hu-chip: rgba(7, 5, 13, 0.55);
  --hu-pre: rgba(5, 4, 10, 0.85);
  --hu-glass-2: rgba(167, 139, 250, 0.06);
  --hu-glass-3: rgba(167, 139, 250, 0.13);
  --hu-border: rgba(167, 139, 250, 0.24);
  --hu-border-weak: rgba(255, 255, 255, 0.09);
  --hu-border-strong: rgba(34, 211, 238, 0.5);
  --hu-border-user: rgba(34, 211, 238, 0.28);
  --hu-glow: rgba(167, 139, 250, 0.45);
  --hu-shadow: rgba(0, 0, 0, 0.5);
  --hu-ok: #4ade80;
  --hu-err: #fb7185;
  --hu-err-bg: rgba(251, 113, 133, 0.25);
  --hu-warn: #fbbf24;
  --hu-info: #22d3ee;
  --hu-grad-line: linear-gradient(90deg, transparent, #a78bfa, #22d3ee, #a78bfa, transparent);
  --hu-grad-line-v: linear-gradient(180deg, #a78bfa, #22d3ee, #a78bfa);
  --hu-loader-bg: #070510;

  /* dirty talk department 🗣 */
  --hu-str-placeholder: "drop your hot take, MVP — the shot clock is fucking running 🏀⏱";
  --hu-str-char-tag: "🏀 starting five · knights after dark 🔥";
  --hu-str-user-tag: "✦ courtside menace (¬‿¬) 🍿 ✦";
  --hu-name-badge: "🏀";
  --hu-str-reasoning: "🗣 timeout — coach is drawing up some filthy play…";
  --hu-str-loadmore: "📼 full game replay, let's go";
  --hu-str-loading: "разогреваем арену… lace up, MVP 🏀";
  --hu-loader-emoji: "🏀";
  --hu-crest: url("data:image/webp;base64,");
  --hu-str-take: "TAKE ";
  --hu-str-msg-label: "PLAY № ";
  --hu-str-token-label: "STATS ";
  --hu-str-timer-label: "SHOT CLOCK ";

  --hu-radius-xl: 24px;
  --hu-radius-lg: 18px;
  --hu-radius-md: 14px;
  --hu-radius-sm: 9px;
  --hu-font-body: 'Manrope', system-ui, sans-serif;
  --hu-font-display: 'Unbounded', 'Manrope', sans-serif;
  --hu-font-mono: 'JetBrains Mono', ui-monospace, monospace;
}

/* ───────────────────────── KEYFRAMES ───────────────────────── */
@keyframes hu-rise {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes hu-pop {
  from { opacity: 0; transform: translateY(14px) scale(0.985); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
@keyframes hu-slide-x {
  from { background-position: 0% 50%; }
  to { background-position: 200% 50%; }
}
@keyframes hu-slide-y {
  from { background-position: 50% 0%; }
  to { background-position: 50% 200%; }
}
@keyframes hu-shimmer {
  from { background-position: 0% 0; }
  to { background-position: 300% 0; }
}
@keyframes hu-breathe {
  0%, 100% { opacity: 0.65; }
  50% { opacity: 1; }
}
@keyframes hu-tag-pulse {
  0%, 100% { opacity: 0.55; letter-spacing: 0.28em; }
  50% { opacity: 0.95; letter-spacing: 0.34em; }
}
@keyframes hu-toast-in {
  from { opacity: 0; transform: translateY(-18px) scale(0.96); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
@keyframes hu-glow-pulse {
  0%, 100% { box-shadow: 0 0 0 0 transparent; }
  50% { box-shadow: 0 0 18px 0 var(--hu-glow); }
}
@keyframes hu-float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-9px); }
}
@keyframes hu-bounce {
  0%, 100% { transform: translateY(0) scale(1, 1); }
  35% { transform: translateY(-16px) scale(0.98, 1.02); }
  50% { transform: translateY(0) scale(1.04, 0.96); }
  62% { transform: translateY(-6px) scale(1, 1); }
}

/* ───────────────────────── GLOBAL ───────────────────────── */
body, html {
  font-family: var(--hu-font-body) !important;
  color: var(--hu-text) !important;
  letter-spacing: 0.01em;
}

::selection { background: var(--hu-accent); color: var(--hu-check-color); }

::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: linear-gradient(180deg, var(--hu-accent), var(--hu-accent-2));
  border-radius: 99px;
  border: none;
  box-shadow: none;
}

#chat {
  background: transparent !important;
  border: none !important;
  padding-left: 6px;
  padding-right: 6px;
  scrollbar-width: thin;
}

/* ───────────────────────── TOP BAR (glass + swapped icons) ───────────────────────── */
#top-bar,
body.no-blur #top-bar {
  background: var(--hu-topbar) !important;
  backdrop-filter: blur(22px) saturate(150%);
  -webkit-backdrop-filter: blur(22px) saturate(150%);
  border: none !important;
  outline: none !important;
  box-shadow: 0 8px 30px var(--hu-shadow) !important;
  border-radius: 0;
}

#top-bar::after {
  content: "";
  position: absolute;
  left: 0; right: 0; bottom: 0;
  height: 2px;
  background: var(--hu-grad-line);
  background-size: 200% 100%;
  animation: hu-slide-x 7s linear infinite;
  pointer-events: none;
}

/* icon swap — Heartbeat technique, mask edition (logically readable icons).
   Only mapped icons are swapped; anything unmapped keeps its default glyph. */
#top-settings-holder .drawer-icon {
  color: var(--hu-icon) !important;
  opacity: 1 !important;
  transition: transform 0.25s ease, color 0.25s ease;
}
#top-settings-holder .drawer-icon:hover { transform: translateY(-2px) scale(1.05); color: var(--hu-accent) !important; }

#leftNavDrawerIcon, #rightNavDrawerIcon, #API-status-top, #WIDrawerIcon,
#advanced-formatting-button .drawer-icon,
#WI-SP-button .drawer-icon,
#user-settings-button .drawer-icon,
#backgrounds-drawer-toggle .drawer-icon,
#extensions-settings-button .drawer-icon,
#persona-management-button .drawer-icon {
  font-size: 0 !important;
  width: 27px !important;
  height: 27px !important;
  min-width: 27px;
  display: flex !important;
  align-items: center;
  justify-content: center;
  overflow: visible;
}
#leftNavDrawerIcon::before, #rightNavDrawerIcon::before, #API-status-top::before, #WIDrawerIcon::before,
#advanced-formatting-button .drawer-icon::before,
#WI-SP-button .drawer-icon::before,
#user-settings-button .drawer-icon::before,
#backgrounds-drawer-toggle .drawer-icon::before,
#extensions-settings-button .drawer-icon::before,
#persona-management-button .drawer-icon::before {
  content: "" !important;
  font-size: 0 !important;
  display: block !important;
  width: 21px !important;
  height: 21px !important;
  background-color: var(--hu-icon);
  -webkit-mask: var(--hu-mask, none) center / contain no-repeat;
  mask: var(--hu-mask, none) center / contain no-repeat;
  transition: background-color 0.25s ease;
}
#top-settings-holder .drawer-icon:hover::before,
#top-settings-holder .drawer-icon.openIcon::before {
  background-color: var(--hu-accent);
}

/* who's who up top — campus edition: sliders / plug / ruler / lorebook / knobs / gallery / puzzle / backpack / grads */
#leftNavDrawerIcon { --hu-mask: url("https://unpkg.com/lucide-static/icons/sliders-horizontal.svg"); }
#API-status-top { --hu-mask: url("https://unpkg.com/lucide-static/icons/plug-zap.svg"); }
#API-status-top.redOverlayGlow { --hu-mask: url("https://unpkg.com/lucide-static/icons/unplug.svg"); }
#API-status-top.redOverlayGlow::before { background-color: var(--hu-err) !important; }
#advanced-formatting-button .drawer-icon { --hu-mask: url("https://unpkg.com/lucide-static/icons/pencil-ruler.svg"); }
#WI-SP-button .drawer-icon { --hu-mask: url("https://unpkg.com/lucide-static/icons/book-marked.svg"); }
#WIDrawerIcon { --hu-mask: url("https://unpkg.com/lucide-static/icons/book-marked.svg"); }
#user-settings-button .drawer-icon { --hu-mask: url("https://unpkg.com/lucide-static/icons/settings-2.svg"); }
#backgrounds-drawer-toggle .drawer-icon { --hu-mask: url("https://unpkg.com/lucide-static/icons/images.svg"); }
#extensions-settings-button .drawer-icon { --hu-mask: url("https://unpkg.com/lucide-static/icons/puzzle.svg"); }
#persona-management-button .drawer-icon { --hu-mask: url("https://unpkg.com/lucide-static/icons/backpack.svg"); }
#rightNavDrawerIcon { --hu-mask: url("https://unpkg.com/lucide-static/icons/graduation-cap.svg"); }

/* extension top bar strip */
#extensionTopBar, #extensionConnectionProfiles {
  border: none !important;
  border-radius: 0 0 var(--hu-radius-md) var(--hu-radius-md) !important;
  background: var(--hu-topbar) !important;
  backdrop-filter: blur(18px);
}
#extensionTopBarChatName, #extensionTopBarSearchInput {
  border: none !important;
  box-shadow: none !important;
  background: none !important;
}

/* ───────────────────────── SEND FORM (Bayou-size box, cheesy animated phrase) ───────────────────────── */
#form_sheld { margin: 0 auto !important; }

#send_form,
body.no-blur #send_form {
  outline: none !important;
  border: none !important;
  background: var(--hu-topbar) !important;
  backdrop-filter: blur(22px) saturate(150%);
  -webkit-backdrop-filter: blur(22px) saturate(150%);
  box-shadow: 0 -8px 30px var(--hu-shadow);
  border-radius: 0;
  border-top: 1px solid var(--hu-border) !important;
}

/* Bayou metrics, glass finish */
#nonQRFormItems {
  position: relative;
  margin: 8px 6px;
  border: 1px solid var(--hu-border);
  border-radius: 14px;
  background: var(--hu-glass-2);
  transition: border-color 0.25s ease, box-shadow 0.25s ease;
}
#nonQRFormItems:focus-within {
  border-color: var(--hu-border-strong);
  box-shadow: 0 0 14px var(--hu-glow);
}

#send_textarea, #send_textarea:focus {
  clip-path: none !important;
  border: none;
  backdrop-filter: none !important;
  background: transparent !important;
  color: var(--hu-text);
  font-family: var(--hu-font-body);
  resize: none !important;
  box-shadow: none !important;
}
#send_textarea::placeholder { color: transparent !important; text-shadow: none !important; }

/* ✨ the pickup line — shimmers like a scholarship kid's future ✨ */
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
  content: var(--hu-str-placeholder);
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  font-family: var(--hu-font-body);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.14em;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 90px);
  pointer-events: none;
  z-index: 10;
  background: linear-gradient(90deg, var(--hu-dim), var(--hu-accent), var(--hu-accent-2), var(--hu-dim));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  animation: hu-shimmer 4s linear infinite, hu-breathe 4s ease-in-out infinite;
}
#nonQRFormItems:has(#send_textarea:focus)::before { display: none !important; }

/* bottom-bar icon swap (Heartbeat technique) */
#options_button, #extensionsMenuButton, #send_but {
  font-size: 0 !important;
  width: 26px;
  height: 26px;
  display: flex !important;
  align-items: center;
  justify-content: center;
  opacity: 1 !important;
  transition: transform 0.25s ease;
}
#options_button::before, #extensionsMenuButton::before, #send_but::before {
  content: "" !important;
  font-size: 0 !important;
  display: block !important;
  width: 21px !important;
  height: 21px !important;
  background-color: var(--hu-icon);
  -webkit-mask: var(--hu-mask, none) center / contain no-repeat;
  mask: var(--hu-mask, none) center / contain no-repeat;
  transition: background-color 0.25s ease;
}
#options_button { --hu-mask: url("https://unpkg.com/lucide-static/icons/layout-grid.svg"); }
#extensionsMenuButton { --hu-mask: url("https://unpkg.com/lucide-static/icons/wand-sparkles.svg"); }
#send_but { --hu-mask: url("https://unpkg.com/lucide-static/icons/send-horizontal.svg"); }
#send_but::before { background-color: var(--hu-accent); filter: drop-shadow(0 0 6px var(--hu-glow)); }
#options_button:hover, #extensionsMenuButton:hover, #send_but:hover { transform: translateY(-2px) scale(1.08); }
#options_button:hover::before, #extensionsMenuButton:hover::before { background-color: var(--hu-accent); }

#send_form .mes_stop { padding: 0 7px; opacity: 1; }
#send_form .mes_stop i { color: var(--hu-err) !important; }
#rightSendForm > div, #leftSendForm > div { margin: 0 2px !important; opacity: 1; }
#rightSendForm div:hover, #leftSendForm div:hover {
  color: var(--hu-accent) !important;
  filter: drop-shadow(0 0 6px var(--hu-glow));
}
#quickPersona img { border-radius: 9px !important; border: 1px solid var(--hu-border) !important; }

/* ───────────────────────── MESSAGE CARDS ─────────────────────────
   avatar: Midnight Ocean sizing — full-width, 350px, soft fade at the bottom
   meta: wine & cherry pie — labeled stat chips, varsity edition            */
#chat .mes {
  position: relative !important;
  display: flex !important;
  flex-direction: column !important;
  margin: 0 auto 34px auto !important;
  width: var(--hu-mes-width, 100%) !important;
  max-width: 100%;
  border: 1px solid var(--hu-border) !important;
  border-radius: var(--hu-radius-xl) !important;
  padding: 0 !important;
  background: var(--hu-card) !important;
  backdrop-filter: blur(14px) saturate(130%);
  -webkit-backdrop-filter: blur(14px) saturate(130%);
  box-shadow: 0 16px 40px var(--hu-shadow);
  overflow: visible !important;
  height: auto !important;
  max-height: none !important;
}
#chat .mes.last_mes { animation: hu-pop 0.45s cubic-bezier(0.2, 0.9, 0.3, 1) both; }
#chat .mes[is_user="true"] { border-color: var(--hu-border-user) !important; }

.mes::before { display: none !important; }

/* ── avatar block: Midnight Ocean spec ── */
.mes .mesAvatarWrapper,
#chat .mes .mesAvatarWrapper {
  order: -1 !important;
  position: relative !important;
  width: 100% !important;
  min-width: 100% !important;
  height: 350px !important;
  flex: 0 0 350px !important;
  overflow: hidden !important;
  margin: 0 !important;
  padding: 0 !important;
  border-radius: var(--hu-radius-xl) var(--hu-radius-xl) 0 0 !important;
  background: transparent !important;
  box-shadow: none !important;
  float: none !important;
  display: flex;
  align-items: flex-start;
  flex-shrink: 0 !important;
}

.mesAvatarWrapper .avatar {
  position: absolute;
  top: 0; left: 0;
  width: 100% !important;
  height: 100% !important;
  margin: 0 !important;
  z-index: 0;
  -webkit-mask-image: linear-gradient(to bottom, black 66%, transparent 100%) !important;
  mask-image: linear-gradient(to bottom, black 66%, transparent 100%) !important;
  pointer-events: none !important;
}

.mesAvatarWrapper .avatar img {
  width: 100% !important;
  height: 100% !important;
  object-fit: cover !important;
  object-position: 50% 0% !important;
  border-radius: 0 !important;
  border: none !important;
  outline: none !important;
  box-shadow: none !important;
  padding: 0 !important;
  background-color: transparent !important;
  transition: transform 0.4s ease;
}
#chat .mes:hover .mesAvatarWrapper .avatar img { transform: scale(1.02); }

/* ── varsity stat chips (wine&cherry style labels, sports renames) ──
   strict grid: left column STATS + SHOT CLOCK, center date, right PLAY №.
   identical height/padding/typography on every chip. */
.mes .mesIDDisplay,
.mes .tokenCounterDisplay,
.mes .mes_timer,
.mes .timestamp {
  position: absolute !important;
  top: 10px !important;
  z-index: 25 !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 6px;
  height: 24px !important;
  box-sizing: border-box !important;
  opacity: 1 !important;
  visibility: visible !important;
  background: var(--hu-chip) !important;
  backdrop-filter: blur(10px) saturate(140%) !important;
  -webkit-backdrop-filter: blur(10px) saturate(140%) !important;
  border: 1px solid var(--hu-border-weak) !important;
  border-radius: 99px !important;
  padding: 0 11px !important;
  margin: 0 !important;
  font-family: var(--hu-font-mono) !important;
  font-size: 10px !important;
  font-weight: 400 !important;
  line-height: 1 !important;
  letter-spacing: 0.06em;
  white-space: nowrap !important;
  color: var(--hu-text) !important;
  left: auto !important;
  transform: none !important;
}
.mes .mesIDDisplay { right: 10px !important; }
.mes .tokenCounterDisplay { left: 10px !important; right: auto !important; }
.mes .mes_timer { left: 10px !important; right: auto !important; top: 40px !important; }
.mes .timestamp {
  left: 50% !important;
  transform: translateX(-50%) !important;
  color: var(--hu-dim) !important;
  font-size: 9px !important;
  letter-spacing: 0.1em;
}
/* empty chips (no value yet) — off the court */
.mes .mes_timer:empty, .mes .tokenCounterDisplay:empty { display: none !important; }

.mesIDDisplay::before,
.tokenCounterDisplay::before,
.mes_timer::before {
  display: inline-block !important;
  font-family: var(--hu-font-display);
  font-size: 7px;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  line-height: 1 !important;
  color: var(--hu-accent);
  margin: 0 !important;
  vertical-align: baseline;
}
.mesIDDisplay::before { content: var(--hu-str-msg-label) !important; }
.tokenCounterDisplay::before { content: var(--hu-str-token-label) !important; }
.mes_timer::before { content: var(--hu-str-timer-label) !important; }
.tokenCounterDisplay::after { display: none !important; }

/* ── name — floating over the avatar fade, full drama ── */
.mes .ch_name .name_text {
  position: absolute;
  top: 297px;
  left: 0;
  right: 0;
  margin: 0 auto;
  z-index: 10;
  width: fit-content;
  max-width: 92%;
  text-align: center;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  font-family: var(--hu-font-display);
  font-size: 19px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--hu-text);
  background: transparent !important;
  text-shadow: 0 2px 18px var(--hu-glow), 0 2px 6px rgba(0, 0, 0, 0.35);
}
.mes .ch_name .name_text::before {
  content: var(--hu-name-badge);
  margin-right: 7px;
  font-size: 15px;
  vertical-align: 2px;
}
/* squad tag under the name */
.mes .ch_name .name_text::after {
  content: var(--hu-str-char-tag);
  display: block;
  margin-top: 4px;
  font-family: var(--hu-font-mono);
  font-size: 8px;
  font-weight: 400;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--hu-accent);
  text-shadow: none;
  animation: hu-tag-pulse 4s ease-in-out infinite;
}
.mes[is_user="true"] .ch_name .name_text::after { content: var(--hu-str-user-tag); color: var(--hu-accent-2); }

/* ── message body ── */
.mes_block,
#chat .mes .mes_block {
  width: 100% !important;
  min-width: 0 !important;
  flex: 1 1 auto !important;
  height: auto !important;
  max-height: none !important;
  min-height: 0 !important;
  overflow: visible !important;
  clear: both !important;
  padding: 8px 20px 16px !important;
  background: none !important;
  border: none !important;
}

.mes .ch_name {
  justify-content: center;
  align-items: center;
  gap: 6px;
}

.mes_text {
  overflow: visible !important;
  height: auto !important;
  max-height: none !important;
  padding: 4px 2px 8px !important;
  font-family: var(--hu-font-body) !important;
  line-height: 1.7 !important;
  text-align: justify;
  text-justify: inter-word;
}
.mes_text p { text-align: justify; }
.mes_text p:empty { display: none; }

.mes_text q {
  color: var(--hu-quote) !important;
  background: var(--hu-glass-2);
  border-radius: 7px;
  padding: 1px 6px;
  line-height: 1.85 !important;
  display: inline;
  -webkit-box-decoration-break: clone;
  box-decoration-break: clone;
  quotes: none !important;
}
.mes_text q::before { content: "🗣 "; font-size: 0.8em; font-style: normal; }

.mes_text em, .mes_text i { color: var(--hu-em); }

/* ── message action buttons — glass pill row ── */
.mes .mes_buttons,
.mes .extraMesButtons {
  display: flex;
  justify-content: center;
  gap: 4px;
}
.mes .mes_buttons .mes_button,
.mes .extraMesButtons > div {
  color: var(--hu-dim) !important;
  font-size: 12px !important;
  padding: 4px 7px;
  border-radius: 9px;
  transition: all 0.2s ease;
  opacity: 0.85;
}
.mes .mes_buttons .mes_button:hover,
.mes .extraMesButtons > div:hover {
  color: var(--hu-accent) !important;
  background: var(--hu-glass-2);
  transform: translateY(-1px);
  opacity: 1;
}
#chat .mes_block .mes_edit_buttons { gap: 4px; }
