  border-radius: 99px !important;
  border: 1px solid var(--hu-border-weak) !important;
  background: var(--hu-glass-2) !important;
  color: var(--hu-text) !important;
  transition: all 0.2s ease;
}
.qr--buttons .qr--button:hover { border-color: var(--hu-border-strong) !important; box-shadow: 0 0 10px var(--hu-glow); }

/* ───────────────────────── LOADING SCREEN — welcome to Hale 🏛 ─────────────────────────
   the ST splash gets a full re-brand: crest, themed phrase, bouncing mascot.
   (applies as soon as the theme CSS kicks in during init) */
#loader {
  background: var(--hu-loader-bg) !important;
  background-image: none !important;
}
#loader .splash-logo { display: none !important; }
#loader.splash-screen::before {
  content: "";
  display: block;
  width: 150px;
  height: 150px;
  margin: 0 auto 18px;
  background: var(--hu-crest) center / contain no-repeat;
  filter: drop-shadow(0 10px 34px var(--hu-glow));
  animation: hu-float 3.2s ease-in-out infinite;
}
#loader .splash-message {
  font-size: 0 !important;
  line-height: 0 !important;
  margin: 0 !important;
}
#loader .splash-message::after {
  content: var(--hu-str-loading);
  display: block;
  font-family: var(--hu-font-mono);
  font-size: 12px;
  font-weight: 400;
  letter-spacing: 0.14em;
  text-transform: lowercase;
  line-height: 1.6;
  text-align: center;
  padding: 10px 16px;
  background: linear-gradient(90deg, var(--hu-dim), var(--hu-accent), var(--hu-accent-2), var(--hu-dim));
  background-size: 300% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  animation: hu-shimmer 4s linear infinite;
}
#loader #load-spinner {
  display: flex !important;
  align-items: center;
  justify-content: center;
  color: transparent !important;
  text-shadow: none !important;
  animation: hu-bounce 1.15s ease-in-out infinite !important;
}
#loader #load-spinner::before {
  content: var(--hu-loader-emoji) !important;
  font-family: 'Segoe UI Emoji', 'Noto Color Emoji', 'Apple Color Emoji', sans-serif !important;
  font-size: 34px;
  line-height: 1;
}
#loader #load-spinner::after { display: none !important; }

/* ───────────────────────── SAFARI ───────────────────────── */
@supports (-webkit-touch-callout: none) {
  #chat { padding-right: 3px; }
  .drawer-content:not(#left-nav-panel):not(#right-nav-panel) { max-width: 100dvw; }
}

/* ───────────────────────── MOBILE — dorm bed mode 🛏 ───────────────────────── */
@media screen and (max-width: 1000px) {
  #chat .mes { width: 100% !important; border-radius: var(--hu-radius-lg) !important; margin-bottom: 26px !important; }
  .mes .mesAvatarWrapper,
  #chat .mes .mesAvatarWrapper {
    height: 260px !important;
    flex: 0 0 260px !important;
    border-radius: var(--hu-radius-lg) var(--hu-radius-lg) 0 0 !important;
  }
  .mes .ch_name .name_text { top: 212px; font-size: 15px; }
  .mes .ch_name .name_text::after { font-size: 7px; }
  .mes_block, #chat .mes .mes_block { padding: 8px 14px 14px !important; }
  .mes .mesIDDisplay, .mes .tokenCounterDisplay, .mes .mes_timer {
    font-size: 9px !important;
    padding: 2px 8px !important;
  }
  .mes .mes_timer { top: 36px !important; }
  #chat { padding-left: 4px; padding-right: 4px; }
  #nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    font-size: 10.5px;
    letter-spacing: 0.1em;
    max-width: calc(100% - 150px);
  }
  ::-webkit-scrollbar { display: none !important; width: 0 !important; }
  html, body, #chat, #sheld, .mes, .mes_block, .mes_text { scrollbar-width: none !important; }
  .mes .mes_block, .mes .mes_buttons { overflow: visible !important; }
  #toast-container > div { min-width: 200px !important; max-width: 86vw !important; }
}

@media screen and (max-width: 700px) {
  .mes .ch_name .name_text { max-width: 88%; }
  .swipe_left { margin-left: -74px !important; }
  .swipe_right { margin-right: -74px !important; }
  .mes_text { text-align: left; }
  .mes_text p { text-align: left; }
}
